import{_ as e,o as l,c as t,a2 as i}from"./chunks/framework.CePymPKS.js";const p=JSON.parse('{"title":"Autable 是什么","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-autable.md","filePath":"guide/what-is-autable.md","lastUpdated":1782043782000}'),o={name:"guide/what-is-autable.md"};function r(n,a,d,s,u,c){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="autable-是什么" tabindex="-1">Autable 是什么 <a class="header-anchor" href="#autable-是什么" aria-label="Permalink to &quot;Autable 是什么&quot;">​</a></h1><p>Autable 是一个代码优先的多维表格系统。它不是 no-code 或 low-code 搭建器，而是把业务表格、表单和工作流拆成可读、可提交、可 review 的文件，让团队和 AI 都能直接维护真实的业务结构。</p><h2 id="设计目标" tabindex="-1">设计目标 <a class="header-anchor" href="#设计目标" aria-label="Permalink to &quot;设计目标&quot;">​</a></h2><p>Autable 的核心目标是让业务系统保持三个性质：</p><ul><li><strong>结构可见</strong>：数据库、表、字段、视图存在于 <code>metadata/main.yml</code>。</li><li><strong>自动化可读</strong>：workflow 是普通 JavaScript 文件，可以组合内置节点。</li><li><strong>录入体验可编程</strong>：form 也是 JavaScript 文件，可以做提交、查询、扫码和自定义动作。</li><li><strong>运行数据可落地</strong>：系统数据、业务数据、历史记录都保存在本地数据目录。</li></ul><h2 id="它解决什么问题" tabindex="-1">它解决什么问题 <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题&quot;">​</a></h2><p>多维表格产品通常把表结构、自动化、表单配置藏在产品内部。这样的系统上手快，但当业务变复杂后，会遇到几个问题：</p><ul><li>很难用 Git review 一次结构变更。</li><li>AI 只能操作 UI 或生成片段，无法直接修改源文件。</li><li>自动化逻辑和数据权限经常分散在不同产品里。</li><li>迁移、备份、部署和审计缺少清晰边界。</li></ul><p>Autable 选择相反的方向：把业务定义放进 Git，把运行数据放进本地数据库，把 UI 当作对这些文件和数据的工作台。</p><h2 id="当前组成" tabindex="-1">当前组成 <a class="header-anchor" href="#当前组成" aria-label="Permalink to &quot;当前组成&quot;">​</a></h2><p>Autable 当前包含：</p><ul><li>Go 后端，负责 API、权限、工作流运行、表单执行和静态前端服务。</li><li>SQLite，用于系统数据和每个业务数据库的行数据。</li><li>LevelDB-compatible 存储，用于 row/workflow 历史记录。</li><li>React 前端，用于表格、视图、表单、工作流和权限管理。</li><li>Git-managed repository，用于 metadata、workflow JavaScript、form JavaScript；本地 <code>config.yml</code> 不进入 Git。</li></ul><h2 id="适合谁" tabindex="-1">适合谁 <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁&quot;">​</a></h2><p>Autable 更适合需要长期维护业务结构的团队：</p><ul><li>内部运营系统、售后系统、采购/库存同步系统。</li><li>需要 AI 参与维护表结构和自动化脚本的团队。</li><li>需要把工作流、表单和权限放在同一个用户体系下的系统。</li><li>希望用 Docker 部署，同时把业务定义保存在 Git 里的团队。</li></ul><h2 id="不是什么" tabindex="-1">不是什么 <a class="header-anchor" href="#不是什么" aria-label="Permalink to &quot;不是什么&quot;">​</a></h2><p>Autable 不是一个追求“所有人都不用写代码”的工具。它允许 UI 操作，但默认假设业务结构最终需要回到代码和 Git。</p>',17)])])}const b=e(o,[["render",r]]);export{p as __pageData,b as default};
